2	// The CLI is exercised as a child process: `npx tsx src/cli.ts` with JSON piped to stdin.
3	import { describe, it, expect } from "vitest";
4	import { spawnSync } from "node:child_process";
5	
6	const validScenario = {
7	  customer: { yearsWithMHPCO: 5 },
8	  steps: [
9	    {
10	      op: "quote",
11	      items: [
12	        { type: "amulet", material: "silver", enchantment: 2, cursed: false },
13	      ],
14	    },
15	  ],
16	};
17	
18	const invalidScenario = {
19	  customer: { yearsWithMHPCO: 5 },
20	  steps: [
21	    {
22	      op: "quote",
23	      items: [
24	        { type: "broomstick", material: "silver", enchantment: 2, cursed: false },
25	      ],
26	    },
27	  ],
28	};
29	
30	const runCli = (scenario: unknown) =>
31	  spawnSync("node_modules/.bin/tsx", ["src/cli.ts"], {
32	    input: JSON.stringify(scenario),
33	    encoding: "utf8",
34	    timeout: 30_000,
35	  });
36	
37	describe("claim-office CLI", () => {
38	  it('should write {"results": [...]} to stdout for a valid scenario', () => {
39	    const result = runCli(validScenario);
40	
41	    expect(JSON.parse(result.stdout)).toEqual({ results: [{ premium: 59 }] });
42	  }, 30_000);
43	  it("should exit with status 0 for a valid scenario", () => {
44	    const result = runCli(validScenario);
45	
46	    expect(result.status).toBe(0);
47	  }, 30_000);
48	  it("should exit with a non-zero status for an invalid scenario", () => {
49	    const result = runCli(invalidScenario);
50	
51	    expect(result.status).not.toBe(0);
52	  }, 30_000);
53	  it("should write an error description to stderr for an invalid scenario", () => {
54	    const result = runCli(invalidScenario);
55	
56	    expect(result.stderr).toContain("broomstick");
57	  }, 30_000);
58	  it("should not write results to stdout for an invalid scenario", () => {
59	    const result = runCli(invalidScenario);
60	
61	    expect(result.stdout).toBe("");
62	  }, 30_000);
63	  // NOT: premium/payout business rules (covered in claim-office.spec.ts),
64	  // malformed/non-JSON stdin handling, CLI flags, output formatting options
65	});
